arguments.file_text:
#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {sizeof(nint)} bytes");

// stackalloc a Span<nint>
Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var v in nints)
    Console.WriteLine($"  {v}");

// stackalloc a Span<nuint>
Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 100;
nuints[1] = 200;
nuints[2] = 300;

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var v in nuints)
    Console.WriteLine($"  {v}");

